// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

	// STRY0100152 
	if(isLoading){
		peformDurationCheck(newValue);
		return;
	}

	peformDurationCheck();

	function peformDurationCheck(newValue){
		// STRY0091294
		var isSuspenseDateRequired = g_scratchpad.isSuspenseDateRequired;
		g_form.setMandatory('u_duration',isSuspenseDateRequired == 'true'); // To make mandatory
	}

}
